    40→const InvalidSinceLabelKey = "kubernetes.io/legacy-token-invalid-since"
    41→
    42→func LegacyClaims(serviceAccount v1.ServiceAccount, secret v1.Secret) (*jwt.Claims, interface{}) {
    43→	return &jwt.Claims{
    44→			Subject: apiserverserviceaccount.MakeUsername(serviceAccount.Namespace, serviceAccount.Name),
    45→		}, &legacyPrivateClaims{
    46→			Namespace:          serviceAccount.Namespace,
    47→			ServiceAccountName: serviceAccount.Name,
    48→			ServiceAccountUID:  string(serviceAccount.UID),
    49→			SecretName:         secret.Name,
    50→		}
    51→}
    52→
    53→const (
    54→	LegacyIssuer     = "kubernetes/serviceaccount"
    55→	LastUsedLabelKey = "kubernetes.io/legacy-token-last-used"
    56→)
    57→
    58→type legacyPrivateClaims struct {
    59→	ServiceAccountName string `json:"kubernetes.io/serviceaccount/service-account.name"`
    60→	ServiceAccountUID  string `json:"kubernetes.io/serviceaccount/service-account.uid"`
    61→	SecretName         string `json:"kubernetes.io/serviceaccount/secret.name"`
    62→	Namespace          string `json:"kubernetes.io/serviceaccount/namespace"`
    63→}
    64→
    65→func NewLegacyValidator(lookup bool, getter ServiceAccountTokenGetter, secretsWriter typedv1core.SecretsGetter) (Validator[legacyPrivateClaims], error) {
    66→	if lookup && getter == nil {
    67→		return nil, errors.New("ServiceAccountTokenGetter must be provided")
    68→	}
    69→	if lookup && secretsWriter == nil {
    70→		return nil, errors.New("SecretsWriter must be provided")
    71→	}
    72→	return &legacyValidator{
    73→		lookup:        lookup,
    74→		getter:        getter,
    75→		secretsWriter: secretsWriter,
    76→	}, nil
    77→}
    78→
    79→type legacyValidator struct {
    80→	lookup        bool
    81→	getter        ServiceAccountTokenGetter
    82→	secretsWriter typedv1core.SecretsGetter
    83→}
    84→
    85→var _ = Validator[legacyPrivateClaims](&legacyValidator{})
    86→
    87→func (v *legacyValidator) Validate(ctx context.Context, tokenData string, public *jwt.Claims, private *legacyPrivateClaims) (*apiserverserviceaccount.ServiceAccountInfo, error) {
    88→	// Make sure the claims we need exist
    89→	if len(public.Subject) == 0 {
    90→		return nil, errors.New("sub claim is missing")
    91→	}
    92→	namespace := private.Namespace
    93→	if len(namespace) == 0 {
    94→		return nil, errors.New("namespace claim is missing")
    95→	}
    96→	secretName := private.SecretName
    97→	if len(secretName) == 0 {
    98→		return nil, errors.New("secretName claim is missing")
    99→	}
   100→	serviceAccountName := private.ServiceAccountName
   101→	if len(serviceAccountName) == 0 {
   102→		return nil, errors.New("serviceAccountName claim is missing")
   103→	}
   104→	serviceAccountUID := private.ServiceAccountUID
   105→	if len(serviceAccountUID) == 0 {
   106→		return nil, errors.New("serviceAccountUID claim is missing")
   107→	}
   108→
   109→	subjectNamespace, subjectName, err := apiserverserviceaccount.SplitUsername(public.Subject)
   110→	if err != nil || subjectNamespace != namespace || subjectName != serviceAccountName {
   111→		return nil, errors.New("sub claim is invalid")
   112→	}
   113→
   114→	if v.lookup {
   115→		// Make sure token hasn't been invalidated by deletion of the secret
   116→		secret, err := v.getter.GetSecret(namespace, secretName)
   117→		if err != nil {
   118→			klog.V(4).Infof("Could not retrieve token %s/%s for service account %s/%s: %v", namespace, secretName, namespace, serviceAccountName, err)
   119→			return nil, errors.New("Token has been invalidated")
   120→		}
   121→		if secret.DeletionTimestamp != nil {
   122→			klog.V(4).Infof("Token is deleted and awaiting removal: %s/%s for service account %s/%s", namespace, secretName, namespace, serviceAccountName)
   123→			return nil, errors.New("Token has been invalidated")
   124→		}
   125→		if subtle.ConstantTimeCompare(secret.Data[v1.ServiceAccountTokenKey], []byte(tokenData)) == 0 {
   126→			klog.V(4).Infof("Token contents no longer matches %s/%s for service account %s/%s", namespace, secretName, namespace, serviceAccountName)
   127→			return nil, errors.New("Token does not match server's copy")
   128→		}
   129→
   130→		// Make sure service account still exists (name and UID)
   131→		serviceAccount, err := v.getter.GetServiceAccount(namespace, serviceAccountName)
   132→		if err != nil {
   133→			klog.V(4).Infof("Could not retrieve service account %s/%s: %v", namespace, serviceAccountName, err)
   134→			return nil, err
   135→		}
   136→		if serviceAccount.DeletionTimestamp != nil {
   137→			klog.V(4).Infof("Service account has been deleted %s/%s", namespace, serviceAccountName)
   138→			return nil, fmt.Errorf("ServiceAccount %s/%s has been deleted", namespace, serviceAccountName)
   139→		}
   140→		if string(serviceAccount.UID) != serviceAccountUID {
   141→			klog.V(4).Infof("Service account UID no longer matches %s/%s: %q != %q", namespace, serviceAccountName, string(serviceAccount.UID), serviceAccountUID)
   142→			return nil, fmt.Errorf("ServiceAccount UID (%s) does not match claim (%s)", serviceAccount.UID, serviceAccountUID)
   143→		}
   144→
   145→		// Track secret-based long-lived service account tokens and add audit annotations and metrics.
   146→		autoGenerated := false
   147→
   148→		// Check if the secret has been marked as invalid
   149→		if invalidSince := secret.Labels[InvalidSinceLabelKey]; invalidSince != "" {
   150→			audit.AddAuditAnnotation(ctx, "authentication.k8s.io/legacy-token-invalidated", secret.Name+"/"+secret.Namespace)
   151→			invalidatedAutoTokensTotal.WithContext(ctx).Inc()
   152→			v.patchSecretWithLastUsedDate(ctx, secret)
   153→			return nil, fmt.Errorf("the token in secret %s/%s for service account %s/%s has been marked invalid. Use tokens from the TokenRequest API or manually created secret-based tokens, or remove the '%s' label from the secret to temporarily allow use of this token", namespace, secretName, namespace, serviceAccountName, InvalidSinceLabelKey)
   154→		}
   155→
   156→		// Check if it is an auto-generated secret-based token
   157→		for _, ref := range serviceAccount.Secrets {
   158→			if ref.Name == secret.Name {
   159→				autoGenerated = true
   160→				warning.AddWarning(ctx, "", "Use tokens from the TokenRequest API or manually created secret-based tokens instead of auto-generated secret-based tokens.")
   161→				audit.AddAuditAnnotation(ctx, "authentication.k8s.io/legacy-token-autogenerated-secret", secret.Name)
   162→				autoGeneratedTokensTotal.WithContext(ctx).Inc()
   163→				break
   164→			}
   165→		}
   166→
   167→		// Check if it's a manually created secret-based token
   168→		if !autoGenerated {
   169→			audit.AddAuditAnnotation(ctx, "authentication.k8s.io/legacy-token-manual-secret", secret.Name)
   170→			manuallyCreatedTokensTotal.WithContext(ctx).Inc()
   171→		}
   172→
   173→		v.patchSecretWithLastUsedDate(ctx, secret)
   174→	}
   175→
   176→	return &apiserverserviceaccount.ServiceAccountInfo{
   177→		Namespace: private.Namespace,
   178→		Name:      private.ServiceAccountName,
   179→		UID:       private.ServiceAccountUID,
   180→	}, nil
   181→}
   182→
   183→func (v *legacyValidator) patchSecretWithLastUsedDate(ctx context.Context, secret *v1.Secret) {
   184→	now := time.Now().UTC()
   185→	today := now.Format("2006-01-02")
   186→	tomorrow := now.AddDate(0, 0, 1).Format("2006-01-02")
   187→	lastUsed := secret.Labels[LastUsedLabelKey]
   188→	if lastUsed != today && lastUsed != tomorrow {
   189→		patchContent, err := json.Marshal(applyv1.Secret(secret.Name, secret.Namespace).WithUID(secret.UID).WithLabels(map[string]string{LastUsedLabelKey: today}))
   190→		if err != nil {
   191→			klog.Errorf("Failed to marshal legacy service account token %s/%s tracking labels, err: %v", secret.Name, secret.Namespace, err)
   192→		} else {
   193→			if _, err := v.secretsWriter.Secrets(secret.Namespace).Patch(ctx, secret.Name, types.MergePatchType, patchContent, metav1.PatchOptions{}); err != nil {
   194→				klog.Errorf("Failed to label legacy service account token %s/%s with last-used date, err: %v", secret.Name, secret.Namespace, err)
   195→			}
   196→		}
   197→	}
   198→}
